func pipeline(matrix: int[][], weights: int[], threshold: int): int {
    val total = 0
    val errors = 0
    val i = 0

    while (i < matrix.length) {
        val rowTotal = 0
        val k = 0

        try {
            for (val k = 0; k < matrix[i].length; k = k + 1) {
                try {
                    val cell = matrix[i][k]
                    val weighted = cell * weights[k] - threshold

                    if (k >= weights.length) {
                        throw new RangeError("weight out of bounds")
                    }

                    if (weighted < 0 && threshold > 0) {
                        try {
                            val fallback = cell * weights[0]
                            if (fallback < 0) {
                                throw "double negative"
                            }
                            rowTotal = rowTotal + fallback
                        } catch (inner: Error) {
                            errors = errors + 1
                            continue
                        } catch {
                            errors = errors + 1
                            break
                        } finally {
                            val innerDone = rowTotal >= 0
                        }
                    } else {
                        rowTotal = rowTotal + weighted
                    }

                    if (rowTotal > threshold * matrix[i].length * weights.length) {
                        break
                    }

                } catch (e: RangeError) {
                    errors = errors + 1
                    continue
                } catch (e: Error) {
                    try {
                        rowTotal = matrix[i][0] * weights[0]
                        if (rowTotal < 0) {
                            throw new Error("recovery failed")
                        }
                    } catch {
                        errors = errors + 1
                        rowTotal = 0
                    } finally {
                        val recovered = rowTotal >= 0
                    }
                } finally {
                    val cellDone = k < matrix[i].length && rowTotal >= 0
                }
            }

            if (rowTotal < 0 && errors == 0) {
                throw new Error("negative row")
            }

            total = total + rowTotal

        } catch (e: Error) {
            errors = errors + 1
            try {
                total = total + matrix[i][0]
                if (total < 0) {
                    throw "total negative"
                }
            } catch (fallback: Error) {
                total = 0
            } catch {
                total = -1
                break
            } finally {
                val rowRecovered = total >= 0
            }
        } finally {
            val rowDone = i < matrix.length && errors >= 0
        }

        i = i + 1

        if (total > threshold * matrix.length * matrix[0].length && errors == 0) {
            break
        }
    }

    return total * threshold - errors * weights[0]
}
